    "select_intro": "Wybierz poprawne pytanie albo krótką odpowiedź w Past Simple.",
    "selects": [
        {
            "label": "a) Did you see him yesterday? / b) Did you saw him yesterday?",
            "prompt": "Która opcja jest poprawna?",
            "answer": "a"
        },
        {
            "label": "a) Did she went home? / b) Did she go home?",
            "prompt": "Która opcja jest poprawna?",
            "answer": "b"
        },
        {
            "label": "a) Yes, I did. / b) Yes, I do.",
            "prompt": "Która opcja jest poprawna?",
            "answer": "a"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Zbuduj pytanie",
    "input_intro": "Postaw did na początku i zostaw główny czasownik w V1.",
    "inputs": [
        {
            "before": "you / watch the film?",
            "after": "→",
            "answer": "Did you watch the film?"
        },
        {
            "before": "she / call you yesterday?",
            "after": "→",
            "answer": "Did she call you yesterday?"
        },
        {
            "before": "they / arrive on time?",
            "after": "→",
            "answer": "Did they arrive on time?"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź błąd w pytaniu albo krótkiej odpowiedzi.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Did he went home?",
            "example_target": "Did he go home?"
        },
        {
            "original": "1. Did he went home?",
            "placeholder": "Popraw zdanie",
            "answer": "Did he go home?"
        },
        {
            "original": "2. You saw her yesterday?",
            "placeholder": "Popraw zdanie",
            "answer": "Did you see her yesterday?"
        },
        {
            "original": "3. Yes, she do.",
            "placeholder": "Popraw odpowiedź",
            "answer": "Yes, she did."
        }
    ]
}
